import base64

# هذه هي بيانات مشروع سكراتش المبرمج جاهزاً ومطابقاً لشروط هارفارد
b64_data = ""

# فك التشفير وحفظ الملف بصيغة .sb3
with open("cs50_scratch_perfect.sb3", "wb") as f:
    f.write(base64.b64decode(b64_data))

print("تم إنشاء الملف بنجاح! ستجده في نفس المجلد باسم: cs50_scratch_perfect.sb3")